        import sailpoint.object.IdentityTrigger;
        import sailpoint.object.IdentityChangeEvent;
        import sailpoint.object.Identity;
        import sailpoint.rapidapponboarding.rule.WrapperRuleLibrary;
        log.debug("Ascension-Lifecycle-Leaver-RequestObject-Wrapper start");

        if(event == null && trigger!=null && Util.nullSafeCaseInsensitiveEq("Ascension-LifecycleEvent-Persona-Leaver",trigger.getName())){
          Identity idty = context.getObjectByName(Identity.class,identityName);
        	event = trigger.createEvent(idty,idty);
        }
        
        List args = new ArrayList();
        args.add(launcher);

        WrapperRuleLibrary.startRequestManager(context,identityName,trigger,event,"Workflow-Ascension-Lifecycle-Leaver",60,args);
        
        log.debug("Ascension-Lifecycle-Leaver-RequestObject-Wrapper end");

        import sailpoint.object.Identity;
        import sailpoint.object.Application;
        import sailpoint.object.Link;
        import java.util.List;
        import java.util.ArrayList;
        

        Identity identity = context.getObjectByName(Identity.class,identityName);
        if(null!=identity){
        String appName = "GSuite";
        Application appObj = context.getObjectByName(Application.class, appName);		
        List links = getIdentityAppLinks(identity, appName);                     
        if (links != null && !links.isEmpty()){
        for(Link appLink:links){
        //Set changePasswordAtNextLogin to false
        changePasswordAtNextLogin(context,appObj,appLink.getNativeIdentity(),false);
        }
        }
        }

        import sailpoint.object.Identity;
        import sailpoint.object.Link;        
        import java.util.List;
        import org.apache.log4j.Level;
        import org.apache.log4j.Logger;
		
        //Logger logger = Logger.getLogger("MDM_Wipe");
        boolean retry = false;
        Identity identity = context.getObjectByName(Identity.class,identityName);
        if(null!=identity){
        boolean hasDevices = hasGSuiteMobileDevice(context,identity);
        if(hasDevices){
        boolean performWipe = true;
        String appName = "DB-Peoplesoft-HCM-Primary";        
        List links = getIdentityAppLinks(identity, appName);
        if (links != null && !links.isEmpty()){
        for(Link appLink:links){
        if(!appLink.isDisabled() && !(Util.nullSafeCaseInsensitiveEq(leaverType, "Immediate"))){
        performWipe = false;
        retry = true;
        }
        }
        }        

        if(performWipe || overrideWipe){
        gsuiteMobileWipe(context,identity);
        retry = false;
        }
        }
        }

        return retry;

        String status = "Retry";

        int maxRetries = workflow.get("mdmMaxRetries");

        int curentRetries = workflow.get("retryCount");
        if(curentRetries<maxRetries){
        curentRetries++;
        wfcontext.setVariable("retryCount", curentRetries);
        } else{
        status = "Exceeded Retry Limit";
        }

        return status;

if (!approved){
return true;
