}

          if (approved) {
          wfcontext.setVariable("overrideWipe", true);
          return true;
          } else {
          return false;  
          }

        import sailpoint.object.Identity;

        Identity refIdentity = context.getObjectByName(Identity.class, identityName);      
        boolean skipCheck = false;

        if(null!=refIdentity.getAttribute("manualTerm") && "yes".equalsIgnoreCase(refIdentity.getAttribute("manualTerm"))){
        skipCheck = true;       
        }
        if (refIdentity.getType() != null) {
        if (!isInMinistriesList(identityName) && refIdentity.getType().equalsIgnoreCase("physician") && !skipCheck){
        needsAdditional = true;
        }
        }

        return needsAdditional;

        import java.util.List;
        import sailpoint.object.Link;

        Identity refIdentity = context.getObjectByName(Identity.class, identityName);        
        List refLinks = getIdADLinks(refIdentity);
        if(refLinks != null){
        for(Link appLink:refLinks){
        if(!appLink.isDisabled()){
        hasEnabledLink = true;
        }
        }
        }       
        return hasEnabledLink;

          if (!approved) {

          return true;

